import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar: React.FC = () => {
  const location = useLocation();

  const navItems = [
    { path: '/', label: 'Home' },
    { path: '/tasks', label: 'Tasks' },
    { path: '/ratings', label: 'Rate Responses' },
  ];

  return (
    <nav style={{
      background: '#0f172a',
      padding: '0 2rem',
      display: 'flex',
      alignItems: 'center',
      height: '60px',
      boxShadow: '0 2px 8px rgba(0,0,0,0.15)'
    }}>
      <span style={{
        color: 'white',
        fontWeight: 700,
        fontSize: '1.1rem',
        marginRight: '2.5rem',
        letterSpacing: '0.3px'
      }}>
        RL Training Platform
      </span>

      <div style={{ display: 'flex', gap: '0.25rem' }}>
        {navItems.map(item => (
          <Link
            key={item.path}
            to={item.path}
            style={{
              color: location.pathname === item.path ? 'white' : '#94a3b8',
              textDecoration: 'none',
              padding: '0.4rem 1rem',
              borderRadius: '6px',
              fontSize: '0.9rem',
              fontWeight: location.pathname === item.path ? 600 : 400,
              background: location.pathname === item.path ? '#1e40af' : 'transparent',
            }}
          >
            {item.label}
          </Link>
        ))}
      </div>
    </nav>
  );
};

export default Navbar;
